+          }
+        ]
+      }
+    },
+    {
+      "name": "command_info_unknown_yields_null_entry",
+      "now_ms": 11002,
+      "argv": ["COMMAND", "INFO", "NO_SUCH_COMMAND"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": null }
+        ]
+      }
+    },
+    {
+      "name": "command_getkeys_returns_empty_array",
+      "now_ms": 11003,
